solution_code:
#include <iostream>

int sumUntilSentinel(int sentinel) {
    int sum = 0;
    int value;
    std::cin >> value;
    while (value != sentinel) {
        sum += value;
        std::cin >> value;
    }
    return sum;
}

int main() {
    std::cout << "Sum: " << sumUntilSentinel(0) << "\n";
    return 0;
}
